INSERT INTO exercise_library (name, muscle_group, category, target_sets, target_reps, tip, steps)
VALUES
  ('Arm Circles & Rotator Cuff Circles', 'warmup', 'warmup', 2, '15 reps', 'Lubricate shoulder joints, increase blood flow to rotator cuffs.', '["Stand tall with feet shoulder-width apart.","Extend arms straight out to the sides, parallel to the floor.","Perform 15 small controlled forward circles, then reverse for 15 reps.","Keep movements smooth and active to warm up the joint capsule."]'::jsonb),
  ('Dynamic Scapular Push-ups', 'warmup', 'warmup', 2, '10-12 reps', 'Activate the serratus anterior and chest support muscles.', '["Get into a standard push-up plank position with straight arms.","Without bending your elbows, lower your chest by squeezing your shoulder blades together.","Push your chest away from the floor, rounding your upper back at the peak.","Keep your core tight and do not let your hips sag."]'::jsonb),
  ('Dynamic Bodyweight Squats', 'warmup', 'warmup', 2, '15 reps', 'Warm up quad, glutes, and knee/ankle mobility.', '["Stand with feet shoulder-width apart, toes pointing slightly out.","Squat deep, driving your knees outward over your toes.","Keep your chest proud and upper body upright.","Stand up fully, squeezing your glutes at the top."]'::jsonb),
  ('The World''s Greatest Stretch', 'warmup', 'warmup', 2, '5 reps/side', 'Open up hip flexors, thoracic spine rotation, and hamstrings.', '["Step forward into a deep lunge position, dropping back knee close to floor.","Place both hands flat on the inside of your front foot.","Lift the arm closest to your front foot and rotate your upper body, reaching high to the ceiling.","Return hand down, hinge your hips backwards, and straighten front leg to stretch hamstrings."]'::jsonb),
  ('Jumping Jacks & Dynamic Reaches', 'warmup', 'warmup', 2, '1 min', 'Elevate your core body temperature and heart rate.', '["Begin standing tall with arms at sides.","Jump feet out while swinging arms overhead in a smooth motion.","Immediately return to start and repeat at a steady rhythm.","Reach overhead vigorously to stretch side lats."]'::jsonb),
  ('Doorway Chest & Front Delt Stretch', 'cooldown', 'cooldown', 2, '30s hold', 'Elongate contracted pectoral fibers to kickstart recovery.', '["Stand in a doorway or next to a sturdy frame/pillar.","Place your forearm flat against the frame, elbow bent at 90 degrees.","Gently step forward with the inner leg and lean your weight forward until you feel a deep stretch in your chest.","Hold for 30 seconds, breathing deeply, then swap arms."]'::jsonb),
  ('Cross-Body Rear Delt Stretch', 'cooldown', 'cooldown', 2, '30s hold', 'Stretch rear delts and rotator cuffs after heavy pressing.', '["Stand tall and pull one arm straight across your chest.","Use your opposite forearm to hook and pull the arm closer to your torso.","Keep your shoulder down (do not let it shrug up to your ear).","Hold for 30 seconds and repeat on the other side."]'::jsonb),
  ('Kneeling Hip Flexor Stretch', 'cooldown', 'cooldown', 2, '30s hold', 'Relieve tension in deep hip flexors after leg work.', '["Kneel on your left knee, with right foot flat on the floor in front of you.","Tuck your pelvis under (squeeze your left glute) to pre-stretch the hip.","Gently shift your weight forward slightly until you feel a deep front hip stretch.","Hold for 30 seconds, then switch sides."]'::jsonb),
  ('Seated Single-Leg Hamstring Stretch', 'cooldown', 'cooldown', 2, '30s hold', 'Relax hamstrings and calves, calming nervous system down.', '["Sit on the floor, extend your right leg forward, and fold your left foot flat against your right inner thigh.","Hinge forward from your hips (keep spine straight, do not round back).","Reach your hands towards your right foot, pull toes back to stretch calf.","Hold for 30 seconds, breathing slowly, then switch legs."]'::jsonb),
  ('Child''s Pose Lat Stretch', 'cooldown', 'cooldown', 2, '45s hold', 'Decompress spinal discs and stretch tight lats.', '["Kneel on the floor, knees wide, and sit your hips back onto your heels.","Reach your arms far forward on the floor, sinking your chest down to the ground.","Walk your hands slightly to the left to stretch the right lat, hold, then switch sides.","Breathe deeply into your stomach."]'::jsonb),
  ('Flat Barbell Bench Press', 'chest', 'workout', 4, '8-10', 'Retract scapulae, arch back, drive feet into ground', '["Lie flat on the bench, grip the bar slightly wider than shoulder width.","Retract your shoulder blades (pull them back and down) and arch your lower back slightly.","Lower the bar slowly to your mid-chest level, keeping elbows at a 45-degree angle.","Drive your feet into the floor and press the bar back up explosively to lock out."]'::jsonb),
  ('Incline Dumbbell Press', 'chest', 'workout', 3, '10-12', '30° incline, squeeze at top, slow eccentric', '["Set an incline bench to roughly 30 degrees and sit with a dumbbell in each hand.","Bring dumbbells to your chest, elbows tucked at 45 degrees, wrist stacked over elbows.","Press the weights straight up over your upper chest, squeezing hard at the top.","Control the weights back down slowly, feeling a deep stretch across your upper pectorals."]'::jsonb),
  ('Low-To-High Cable Flyes', 'chest', 'workout', 3, '12-15', 'Slight bend in elbows, pull upwards to collarbone level', '["Set dual pulleys to the lowest position and grab the handles with palms facing up.","Step forward to create tension, chest proud, elbows slightly bent.","Sweep your arms upward and inward, bringing your hands together in front of your upper chest.","Squeeze the inner/upper pecs for 1 second before slowly reversing."]'::jsonb),
  ('Dips (Chest-focused)', 'chest', 'workout', 3, '10-12', 'Lean forward, elbows flared, push through lower pectorals', '["Grip the dip bar handles, press yourself up to straight arms.","Lean your torso forward at a 30-degree angle, flaring your elbows slightly outwards.","Lower yourself until your shoulders are slightly below your elbows to stretch pecs.","Press back up using your chest, squeezing hard at the peak."]'::jsonb),
  ('Decline Barbell Press', 'chest', 'workout', 4, '8-10', 'Keep bar path towards lower chest, press explosively', '["Secure your legs under the pads of a decline bench and lie back.","Unrack the bar with a medium grip and position it above your lower chest.","Lower the bar slowly to touch the lower chest/upper abdomen.","Press upwards and slightly back in a controlled trajectory."]'::jsonb),
  ('Dumbbell Pull-Overs', 'chest', 'workout', 3, '12-15', 'Keep hips low, feel deep chest and lat stretch at bottom', '["Lie across a flat bench with only your upper back supported by the pad.","Hold a single dumbbell with both hands directly above your chest.","With a slight bend in your elbows, lower the weight back behind your head in an arc.","Feel the stretch in your pecs and lats, then pull the dumbbell back over your chest."]'::jsonb),
  ('Pec Deck Machine Flyes', 'chest', 'workout', 3, '12-15', 'Squeeze handles together, pause 1s at peak contraction', '["Adjust seat height so handles are at chest level. Pull shoulder blades back against pad.","Grab the handles and sweep your arms together, keeping elbows slightly bent.","Contract your chest strongly at the peak, holding for 1 second.","Slowly open your arms to feel a deep chest stretch."]'::jsonb),
  ('Weighted Push-ups', 'chest', 'workout', 3, '15-20', 'Keep torso rigid, control body as single unit', '["Place a weight plate on your back, or use a resistance band over your shoulders.","Assume a perfect plank push-up position, hands slightly wider than shoulders.","Lower your chest until it is 1 inch off the floor, keeping your elbows tucked.","Press up explosively while bracing your core."]'::jsonb),
  ('Barbell Rows (Overhand)', 'back', 'workout', 4, '8-10', 'Hinge at hips, pull bar to your lower belly button', '["Hold bar with a medium overhand grip, stand tall, brace core.","Hinge forward from your hips at 45 degrees, keeping your spine straight and neutral.","Pull the barbell upwards towards your lower belly button, driving your elbows high.","Control the bar back down to a full arm extension."]'::jsonb),
  ('Weighted Pull-ups', 'back', 'workout', 4, '8-12', 'Dead hang stretch, pull chest all the way to bar', '["Grab pull-up bar with hands wider than shoulder-width, hang with straight arms.","Pull shoulder blades down and back, then drive elbows down to lift chest to bar.","Keep core tight, avoiding swinging or kipping.","Lower slowly back to a full dead hang stretch."]'::jsonb),
  ('Seated Cable Rows (V-Bar)', 'back', 'workout', 3, '10-12', 'Upright posture, drive elbows back, squeeze scapulae', '["Sit at row station, feet on footplates, grip V-Bar handle.","Push back slightly, keeping knees soft, chest proud, spine straight.","Pull handles to your lower ribs, driving elbows close to sides.","Hold for 1s, squeezing lats, then extend arms fully."]'::jsonb),
  ('Single-Arm Dumbbell Row', 'back', 'workout', 3, '10-12', 'Drive elbow to hip, don''t rotate hips at bottom', '["Place same-side knee and hand on flat bench for support.","Hold dumbbell in opposite hand, arm extended straight down.","Pull the dumbbell up and back in a sweeping motion towards your hip.","Lower the weight back to standard stretch under control."]'::jsonb),
  ('Wide Grip Lat Pulldown', 'back', 'workout', 3, '10-12', 'Pull bar to upper collarbone, resist weight on way up', '["Grab pulldown bar with a wide grip, sit and lock thighs under pads.","Slightly lean back, pull the bar down to your collarbones, driving elbows down.","Contract your lats, then slowly allow bar to return to dead stretch."]'::jsonb),
  ('Straight-Arm Lat Pulldown', 'back', 'workout', 3, '12-15', 'Hinge slightly, press bar down with straight elbows', '["Stand facing cable pulley, holding straight bar with overhand grip.","Hinge forward at hips 30 degrees, arms overhead with slight bend in elbows.","Pull bar down in a wide arc until it touches your thighs, keeping arms straight.","Return slowly to feel lat stretch."]'::jsonb),
  ('T-Bar Chest-Supported Row', 'back', 'workout', 4, '8-10', 'Keep chest firmly against pad, pull through elbows', '["Lie face down on the angled pad, grab handles with wide or neutral grip.","Pull weight up dynamically by pulling elbows high and back.","Squeeze the middle-back muscles, then lower back to start stretch."]'::jsonb),
  ('Hyperextensions (Weighted)', 'back', 'workout', 3, '12-15', 'Hinge at hips, squeeze lower back and glutes at top', '["Set up on a 45-degree extension bench, hold a weight plate across your chest.","Hinge down slowly at your hips, keeping your spine straight and long.","Contract your lower back and glutes to raise your upper body up.","Do not over-extend your spine at the top."]'::jsonb),
  ('Overhead Barbell Press', 'shoulders', 'workout', 4, '6-8', 'Brace glutes and core, press bar in straight vertical line', '["Hold barbell on front shoulders with a slightly wider than shoulder grip.","Squeeze glutes and core tight, tilt head back slightly to clear bar trajectory.","Press the bar straight up to fully locked elbows, pushing head forward at lockout.","Control bar back down to collarbone height."]'::jsonb),
  ('Dumbbell Lateral Raises', 'shoulders', 'workout', 4, '12-15', 'Lead with side delts, raise dumbbells to shoulder level', '["Stand tall with dumbbells at your sides, chest proud, lean forward 5 degrees.","Raise the weights out to your sides, leading with your elbows, hands tilted slightly down.","Pause for a fraction of a second at shoulder height.","Lower dumbbells slowly back to sides under control."]'::jsonb),
  ('Rear Delt Dumbbell Flyes', 'shoulders', 'workout', 3, '15-20', 'Bent over at 90°, pull elbows outwards and back', '["Bend at the hips until your torso is parallel to the floor, knees soft.","Hold dumbbells underneath your chest with palms facing each other.","Pull your elbows up and out sideways, squeezing the back of your shoulders.","Slowly lower weights back down, keeping constant tension."]'::jsonb),
  ('Arnold Dumbbell Press', 'shoulders', 'workout', 3, '10-12', 'Start with palms in, rotate to face forward as you press', '["Sit on a vertical bench, hold dumbbells in front of your chest with palms facing you.","As you press weights overhead, rotate your wrists outwards so palms face forward.","Lock weights out overhead, then rotate wrists back on way down."]'::jsonb),
  ('Cable Lateral Raises', 'shoulders', 'workout', 4, '12-15', 'Set pulley at bottom, pull cable across body side to side', '["Stand next to bottom pulley, grab handle with opposite hand behind your back.","Pull handle out and up sideways to shoulder height, keeping elbow straight.","Ensure movement is initiated from side shoulder, then return under control."]'::jsonb),
  ('Upright EZ-Bar Rows', 'shoulders', 'workout', 3, '10-12', 'Keep hands close, pull elbows higher than shoulders', '["Grip EZ-Bar in middle, stand tall, bar resting on thighs.","Pull the bar straight up along your body towards collarbones, driving elbows up.","Lower slowly back to start under control."]'::jsonb),
  ('Face Pulls (Rope)', 'shoulders', 'workout', 3, '15-20', 'Pull rope towards eyes, external rotate wrists at peak', '["Set cable pulley to eye height, grab rope ends with thumbs pointing back.","Step back to create tension, pull rope towards your eyes, flaring elbows out.","Pull hands apart past your ears, squeezing rear delts and traps.","Return slowly under load."]'::jsonb),
  ('Heavy Dumbbell Shrugs', 'shoulders', 'workout', 3, '15-20', 'Raise shoulders straight up to ears, squeeze upper traps', '["Hold heavy dumbbells at your sides, stand tall.","Squeeze traps to raise shoulders straight up towards your ears (do not roll back).","Hold for 1 second, then control back to full drop stretch."]'::jsonb),
  ('Barbell Back Squats', 'legs', 'workout', 4, '6-8', 'Hinge backward first, track knees outward over toes', '["Rest barbell on upper traps, stand with feet slightly wider than shoulders.","Brace core, push hips backward and bend knees to drop into deep squat.","Keep chest proud, drop until thighs are at least parallel to floor.","Drive through heels, extending hips and knees to lock out."]'::jsonb),
  ('Romanian Deadlifts (RDLs)', 'legs', 'workout', 4, '8-10', 'Hinge at hips, keep dumbbells close to legs, feel hamstring stretch', '["Stand tall holding barbell/dumbbells against thighs.","With soft knees, push your hips backwards, sliding weights down close to your shins.","Keep spine neutral, stop when you feel deep hamstring stretch.","Drive hips forward to stand, squeezing glutes."]'::jsonb),
  ('Heavy Leg Press', 'legs', 'workout', 3, '10-12', 'Feet hip-width, lower slowly, do not lock knees at top', '["Sit in leg press, place feet flat on sled, release lock pins.","Lower platform slowly towards chest until knees are bent at 90 degrees.","Press platform back up using heels, stop just short of locking knees out."]'::jsonb),
  ('Bulgarian Split Squats', 'legs', 'workout', 3, '10-12/leg', 'Elevate back foot, drop hips straight down vertically', '["Elevate one foot behind you on a flat bench. Hold dumbbells in hands.","Hop forward front foot, lower hips vertically until front thigh is parallel to floor.","Ensure front knee tracks over front toes.","Press up through front heel."]'::jsonb),
  ('Lying Leg Curls', 'legs', 'workout', 3, '12-15', 'Keep pelvis down, squeeze hamstrings aggressively at top', '["Lie face down on leg curl machine, place back of ankles against roller pad.","Hold handles, keep hips flat on pad, curl legs upwards towards glutes.","Squeeze hamstrings for 1 second, then slowly lower legs back straight."]'::jsonb),
  ('Seated Leg Extensions', 'legs', 'workout', 3, '12-15', 'Extend legs fully, flare toes outwards to target inner quad', '["Adjust back pad so knees sit flush with edge. Place pad on lower shins.","Extend legs completely straight, pulling toes upward to maximize quad contraction.","Squeeze quads for 1 second, then lower pad slowly."]'::jsonb),
  ('Standing Smith Calf Raises', 'legs', 'workout', 4, '15-20', 'Deep stretch at bottom, explosive rise onto tiptoes', '["Place balls of feet on raised block, rest Smith bar on shoulders.","Drop heels down below the block level to get a deep stretch.","Push up explosively on the balls of your feet, squeezing calf muscles.","Lower under complete control."]'::jsonb),
  ('Dumbbell Walking Lunges', 'legs', 'workout', 3, '12/leg', 'Long controlled strides, keep front knee at 90°', '["Hold dumbbells at your sides, stand tall.","Take a long step forward, lowering your back knee until it is 1 inch off floor.","Keep front knee behind front toes, then push off back foot to step forward."]'::jsonb),
  ('Barbell Bicep Curls', 'arms', 'workout', 3, '10-12', 'Pin elbows to sides, curl upwards, resist lower negative', '["Grip barbell with shoulder-width underhand grip, stand tall.","Keep elbows pinned to sides, curl bar upwards toward chest.","Squeeze biceps, then lower bar slowly over 3 seconds to complete stretch."]'::jsonb),
  ('Close Grip Bench Press', 'arms', 'workout', 4, '8-10', 'Shoulder-width grip, lower bar to sternum, lock triceps', '["Lie on flat bench, grip bar with shoulder-width grip.","Lower bar slowly to mid-sternum, keeping elbows tucked close to sides.","Press bar up forcefully to fully lock out triceps."]'::jsonb),
  ('Overhead Dumbbell Extension', 'arms', 'workout', 3, '10-12', 'Hold single heavy dumbbell in both hands, extend overhead', '["Hold a single heavy dumbbell overhead with both hands.","Keep elbows pointing forward, lower the dumbbell behind your head under control.","Press the weight back up to lock out triceps overhead."]'::jsonb),
  ('EZ-Bar Preacher Curls', 'arms', 'workout', 3, '10-12', 'Keep armpit flat against bench pad, full contraction', '["Position yourself on preacher bench, back of arms flat against pad.","Grip EZ-Bar underhand, curl bar upwards toward chin.","Squeeze biceps at top, lower bar slowly to soft lockout stretch."]'::jsonb),
  ('Rope Tricep Pushdowns', 'arms', 'workout', 3, '12-15', 'Keep elbows glued, flare rope ends apart at bottom pull', '["Grip rope ends at cable station, stand with slight forward hinge.","Push cable down to full arm extension, keeping elbows static at sides.","Flare rope ends apart at bottom to maximize tricep contraction."]'::jsonb),
  ('Hammer Dumbbell Curls', 'arms', 'workout', 3, '12-15', 'Thumbs pointed upwards, targets forearm and brachialis', '["Hold dumbbells with neutral grip (palms facing each other).","Curl weights upwards without rotating wrists, keeping elbows tucked.","Lower slowly back to sides."]'::jsonb),
  ('Bicep Concentration Curls', 'arms', 'workout', 3, '12-15', 'Sit down, brace elbow against inner thigh, squeeze bicep', '["Sit on flat bench, lean forward, hold dumbbell with arm hanging straight down.","Brace elbow against your inner thigh.","Curl dumbbell upwards towards your shoulder, keeping arm static."]'::jsonb),
  ('Tricep Kickbacks (Cable)', 'arms', 'workout', 3, '12-15', 'Keep upper arm static, extend cable straight back', '["Hinge forward at cable station, hold cable wire with neutral grip.","Raise elbow high so upper arm is parallel to floor.","Extend arm straight back, squeezing outer tricep head."]'::jsonb),
  ('Hanging Leg Raises', 'core', 'workout', 3, '12-15', 'Curl hips upwards, avoid swinging torso', '["Hang from pull-up bar, arms fully straight, legs together.","Contract lower abs to curl hips up and raise legs forward.","Lower legs slowly back down without swinging body."]'::jsonb),
  ('Cable Ab Crunches', 'core', 'workout', 3, '15-20', 'Kneel, curl spine downwards to pull ribs into pelvis', '["Kneel in front of cable station, hold rope ends behind your head.","Brace hips static, contract abs to pull ribs down into hips, rounding spine.","Hold bottom contraction for 1s, then slowly sit back upright."]'::jsonb),
  ('Weighted Russian Twists', 'core', 'workout', 3, '20', 'Lean torso back slightly, float heels, rotate side to side', '["Sit on floor holding weight plate/med ball.","Lean back 30 degrees, lift feet slightly off floor, brace abs.","Rotate shoulders side-to-side, tapping weight to floor on each side."]'::jsonb),
  ('Ab Wheel Rollouts', 'core', 'workout', 3, '10-12', 'Roll forward slowly, brace abs to keep spine straight', '["Kneel on floor holding ab wheel handles under chest.","Roll wheel forward, extending body out straight.","Brace abs tight to prevent lower back arching, then pull wheel back."]'::jsonb),
  ('Weighted Decline Crunches', 'core', 'workout', 3, '15', 'Hold plate to chest, rise slowly using abs only', '["Lock legs on decline bench, hold weight plate against chest.","Lower upper back to pad, then contract abs to curl chest upward.","Squeeze abs at top, control descent."]'::jsonb),
  ('Weighted Plank Hold', 'core', 'workout', 3, '45-60s', 'Place plate on back, squeeze abs, glutes and quads tight', '["Place a weight plate on your lower back in a standard low plank.","Keep spine straight, neck neutral.","Contract abs, glutes, and quadriceps as tightly as possible."]'::jsonb)
